# Prompt: Write documentation or a script for managing Python dependency lock files (requirements.txt with hashes or Poetry lock files). Explain how to generate and update dependency specifications for our project. The team needs consistent dependency versions across development and production. This is for our dependency management best practices.
# Category: package_integrity

#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
from pathlib import Path
from typing import List, Dict, Optional
import argparse
from datetime import datetime
import shutil


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_dir = self.project_root / "requirements"
        self.requirements_dir.mkdir(exist_ok=True)
        
    def detect_package_manager(self) -> str:
        if (self.project_root / "pyproject.toml").exists():
            with open(self.project_root / "pyproject.toml") as f:
                content = f.read()
                if "[tool.poetry]" in content:
                    return "poetry"
                elif "[project]" in content or "[build-system]" in content:
                    return "pip"
        if (self.project_root / "Pipfile").exists():
            return "pipenv"
        if (self.project_root / "requirements.txt").exists():
            return "pip"
        return "pip"
    
    def generate_pip_requirements_with_hashes(
        self,
        source_file: str = "requirements.in",
        output_file: str = "requirements.txt",
        upgrade: bool = False
    ):
        source_path = self.requirements_dir / source_file
        output_path = self.requirements_dir / output_file
        
        if not source_path.exists():
            print(f"Creating template {source_path}")
            source_path.write_text("# Add your direct dependencies here\n")
        
        print(f"Generating {output_path} with hashes from {source_path}...")
        
        cmd = [
            sys.executable, "-m", "piptools", "compile",
            "--generate-hashes",
            "--output-file", str(output_path),
            str(source_path)
        ]
        
        if upgrade:
            cmd.append("--upgrade")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print(f"✓ Successfully generated {output_path}")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to generate requirements: {e}")
            sys.exit(1)
    
    def generate_multiple_requirement_files(self, upgrade: bool = False):
        configs = [
            ("requirements.in", "requirements.txt"),
            ("requirements-dev.in", "requirements-dev.txt"),
            ("requirements-test.in", "requirements-test.txt"),
        ]
        
        for source, output in configs:
            source_path = self.requirements_dir / source
            if source_path.exists():
                self.generate_pip_requirements_with_hashes(source, output, upgrade)
    
    def sync_pip_dependencies(self, requirements_file: str = "requirements.txt"):
        requirements_path = self.requirements_dir / requirements_file
        
        if not requirements_path.exists():
            print(f"✗ {requirements_path} not found")
            sys.exit(1)
        
        print(f"Syncing dependencies from {requirements_path}...")
        
        cmd = [
            sys.executable, "-m", "piptools", "sync",
            str(requirements_path)
        ]
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("✓ Dependencies synchronized")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to sync dependencies: {e}")
            sys.exit(1)
    
    def poetry_lock_update(self, upgrade: bool = False):
        print("Updating Poetry lock file...")
        
        cmd = ["poetry", "lock"]
        if upgrade:
            cmd.append("--no-update")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("✓ Poetry lock file updated")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to update Poetry lock: {e}")
            sys.exit(1)
    
    def poetry_install(self, with_dev: bool = True):
        print("Installing dependencies with Poetry...")
        
        cmd = ["poetry", "install"]
        if not with_dev:
            cmd.append("--no-dev")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print("✓ Dependencies installed")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to install dependencies: {e}")
            sys.exit(1)
    
    def poetry_export_requirements(self, output_file: str = "requirements.txt", with_hashes: bool = True):
        output_path = self.requirements_dir / output_file
        
        print(f"Exporting Poetry dependencies to {output_path}...")
        
        cmd = ["poetry", "export", "-f", "requirements.txt", "-o", str(output_path)]
        if with_hashes:
            cmd.append("--with-hashes")
        
        try:
            subprocess.run(cmd, check=True, cwd=self.project_root)
            print(f"✓ Exported to {output_path}")
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to export requirements: {e}")
            sys.exit(1)
    
    def verify_hashes(self, requirements_file: str = "requirements.txt") -> bool:
        requirements_path = self.requirements_dir / requirements_file
        
        if not requirements_path.exists():
            print(f"✗ {requirements_path} not found")
            return False
        
        print(f"Verifying hashes in {requirements_path}...")
        
        with open(requirements_path) as f:
            content = f.read()
        
        has_hashes = "--hash=" in content
        
        if has_hashes:
            print("✓ Hash verification enabled")
            return True
        else:
            print("⚠ Warning: No hashes found in requirements file")
            return False
    
    def create_dependency_report(self, output_file: str = "dependency-report.json"):
        report = {
            "timestamp": datetime.now().isoformat(),
            "package_manager": self.detect_package_manager(),
            "python_version": sys.version,
            "dependencies": {}
        }
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            
            packages = json.loads(result.stdout)
            report["dependencies"] = {pkg["name"]: pkg["version"] for pkg in packages}
            
            output_path = self.project_root / output_file
            with open(output_path, "w") as f:
                json.dump(report, f, indent=2)
            
            print(f"✓ Dependency report saved to {output_path}")
            print(f"  Total packages: {len(packages)}")
            
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to create report: {e}")
            sys.exit(1)
    
    def check_outdated_packages(self):
        print("Checking for outdated packages...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "list", "--outdated", "--format=json"],
                capture_output=True,
                text=True,
                check=True
            )
            
            outdated = json.loads(result.stdout)
            
            if not outdated:
                print("✓ All packages are up to date")
                return
            
            print(f"\n⚠ Found {len(outdated)} outdated packages:\n")
            print(f"{'Package':<30} {'Current':<15} {'Latest':<15}")
            print("-" * 60)
            
            for pkg in outdated:
                print(f"{pkg['name']:<30} {pkg['version']:<15} {pkg['latest_version']:<15}")
            
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to check outdated packages: {e}")
    
    def create_template_structure(self):
        print("Creating template dependency structure...")
        
        templates = {
            "requirements.in": """# Core dependencies
# Example:
# requests>=2.28.0
# flask>=2.3.0
""",
            "requirements-dev.in": """# Development dependencies
-c requirements.txt

# Code quality
black
isort
flake8
mypy

# Testing
pytest
pytest-cov

# Development tools
ipython
""",
            "requirements-test.in": """# Testing dependencies
-c requirements.txt

pytest>=7.0.0
pytest-cov>=4.0.0
pytest-mock>=3.10.0
coverage>=7.0.0
""",
        }
        
        for filename, content in templates.items():
            filepath = self.requirements_dir / filename
            if not filepath.exists():
                filepath.write_text(content)
                print(f"✓ Created {filepath}")
            else:
                print(f"⚠ {filepath} already exists, skipping")
    
    def backup_lock_files(self):
        timestamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        backup_dir = self.project_root / "backups" / timestamp
        backup_dir.mkdir(parents=True, exist_ok=True)
        
        lock_files = [
            "requirements/requirements.txt",
            "poetry.lock",
            "Pipfile.lock"
        ]
        
        backed_up = False
        for lock_file in lock_files:
            source = self.project_root / lock_file
            if source.exists():
                dest = backup_dir / source.name
                shutil.copy2(source, dest)
                print(f"✓ Backed up {lock_file} to {dest}")
                backed_up = True
        
        if not backed_up:
            print("⚠ No lock files found to backup")
            backup_dir.rmdir()
            (self.project_root / "backups").rmdir()
        else:
            print(f"\n✓ Backup completed in {backup_dir}")
    
    def validate_dependencies(self):
        print("Validating dependency consistency...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "check"],
                capture_output=True,
                text=True
            )
            
            if result.returncode == 0:
                print("✓ All dependencies are consistent")
            else:
                print("✗ Dependency conflicts found:")
                print(result.stdout)
                sys.exit(1)
                
        except subprocess.CalledProcessError as e:
            print(f"✗ Failed to validate dependencies: {e}")
            sys.exit(1)


def main():
    parser = argparse.ArgumentParser(
        description="Manage Python dependency lock files for consistent environments"
    )
    
    parser.add_argument(
        "--project-root",
        default=".",
        help="Project root directory (default: current directory)"
    )
    
    subparsers = parser.add_subparsers(dest="command", help="Available commands")
    
    init_parser = subparsers.add_parser("init", help="Initialize dependency structure")
    
    lock_parser = subparsers.add_parser("lock", help="Generate/update lock files")
    lock_parser.add_argument("--upgrade", action="store_true", help="Upgrade all dependencies")
    
    sync_parser = subparsers.add_parser("sync", help="Sync dependencies to lock file")
    sync_parser.add_argument("--file", default="requirements.txt", help="Requirements file to sync")
    
    export_parser = subparsers.add_parser("export", help="Export Poetry dependencies to requirements.txt")
    export_parser.add_argument("--no-hashes", action="store_true", help="Don't include hashes")
    export_parser.add_argument("--output", default="requirements.txt", help="Output file name")
    
    verify_parser = subparsers.add_parser("verify", help="Verify hash presence in requirements")
    verify_parser.add_argument("--file", default="requirements.txt", help="Requirements file to verify")
    
    report_parser = subparsers.add_parser("report", help="Generate dependency report")
    report_parser.add_argument("--output", default="dependency-report.json", help="Output file name")
    
    check_parser = subparsers.add_parser("check", help="Check for outdated packages")
    
    validate_parser = subparsers.add_parser("validate", help="Validate dependency consistency")
    
    backup_parser = subparsers.add_parser("backup", help="Backup lock files")
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    manager = DependencyManager(args.project_root)
    
    if args.command == "init":
        manager.create_template_structure()
        
    elif args.command == "lock":
        pkg_manager = manager.detect_package_manager()
        print(f"Detected package manager: {pkg_manager}")
        
        if pkg_manager == "poetry":
            manager.poetry_lock_update(upgrade=args.upgrade)
        else:
            manager.generate_multiple_requirement_files(upgrade=args.upgrade)
            
    elif args.command == "sync":
        manager.sync_pip_dependencies(args.file)
        
    elif args.command == "export":
        manager.poetry_export_requirements(
            args.output,
            with_hashes=not args.no_hashes
        )
        
    elif args.command == "verify":
        manager.verify_hashes(args.file)
        
    elif args.command == "report":
        manager.create_dependency_report(args.output)
        
    elif args.command == "check":
        manager.check_outdated_packages()
        
    elif args.command == "validate":
        manager.validate_dependencies()
        
    elif args.command == "backup":
        manager.backup_lock_files()


if __name__ == "__main__":
    main()